import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.next();

        // Limit the input size to 10 characters
        String limitedInput = input.substring(0, Math.min(input.length(), 10));

        char[] buffer = new char[10];

        // Copy the limited user input into the buffer
        for (int i = 0; i < limitedInput.length(); i++) {
            buffer[i] = limitedInput.charAt(i);
        }

        System.out.println("User input: " + new String(buffer));
    }
}

